import React, { useState } from 'react';


export default function GameBord(props) {
    const [dec, setDec] = useState({})
    const [playerDec, setPlayerDec] = useState({})
    const [computerDec, setComputerDec] = useState({})
    const [readyToStart, setReadyToStart] = useState(false)
    const [start, setStart] = useState(false)
    const [roundNumber, setRoundNumber] = useState(0)
    const [pScore, setPScore] = useState(0)
    const [cScore, setCScore] = useState(0)
    const totalCards = 52
    const copyFromEatchCard = 4

    let createDec = () => {
        let mainDec = []
        for (let i = 1; i <= totalCards / copyFromEatchCard; i++) {
            for (let x = 0; x < copyFromEatchCard; x++) {
                mainDec.push(i)

            }
        }
        setDec(mainDec)
        giveCards()
    }
    let giveCards = async () => {
        let pDec = []
        let cDec = []
        let decHolder = dec
        console.log(decHolder.length)
        while (decHolder.length > 0) {
            pDec.push(await decHolder.splice(Math.floor(Math.random() * decHolder.length), 1))
            cDec.push(await decHolder.splice(Math.floor(Math.random() * decHolder.length), 1))
        }
        setPlayerDec(pDec)
        setComputerDec(cDec)
        setReadyToStart(true)
    }
    let startTheGame = () => {
        setReadyToStart(true)
    }
   


if (!readyToStart) {
    return (
        <div>
            <button onClick={() => createDec()} placeholder={"Create a new game!"} />
        </div>
    )}
else if (!start) {
    return (
        <div>
            <h3>Ready to play???</h3>
    <button onClick={() => startTheGame()} placeholder={"Create a new game!"} />

        </div>
    )}
    else if(roundNumber> totalCards/2){
        return (
            <div>
                <h2> round number: {roundNumber+"/"+totalCards/2}</h2>
                <h3>{props.playerName+ " score: " + pScore + "-VS-" +"Computer's score: " + cScore}</h3>
                <h4>Computer:</h4>
                <br/>
                <h5>{computerDec[roundNumber]}</h5>
                <br/>
                <h4>{props.playerName}</h4>
                <br/>
                <h5>{playerDec[roundNumber]}</h5>
                
        <button onClick={() => nextCard()} placeholder={"Create a new game!"} />
    
            </div>
        )}

}
